-- ===== recall_events (openFDA, verified_official, upsert on dedup_key) =====
-- brand-match recalls to known brands (BRAND-LEVEL only; never implies exact product recall)
update public.recall_events re set brand_id=b.id, brand_match_level='brand' from public.food_brands b where re.brand_id is null and re.raw_payload is null and re.reason is not null and position(lower(split_part(b.name,' ',1)) in lower(re.reason))>0 and length(split_part(b.name,' ',1))>3;

