insert into public.lab_tests(level,brand_id,contaminant_category,substance,result_value,unit,status,test_date,lab_name,source_url,evidence_status,confidence_score,raw_payload) values ('brand',(select id from public.food_brands where name='Freshpet' limit 1),'bpa_bps','heavy metals; bisphenols; phthalates; acrylamide; pesticides; glyphosate','','','pass','2026-02-12','Ellipse Analytics (ISO 17025) via Clean Label Project','https://cleanlabelproject.org/dog-food-study/','verified_lab',null,jsonb_build_object('note','Only brand listed as Clean Label Project CERTIFIED in the Feb-2026 ISO-17025 study (independent testing for 100+ contaminants). Brand-level certification, not a per-lot COA.','source_type','third_party_lab_summary','evidence_grade','verified_lab','product','Full portfolio (Clean Label Project Certified)','accessed','2026-06-25'));
insert into public.lab_tests(level,brand_id,contaminant_category,substance,result_value,unit,status,test_date,lab_name,source_url,evidence_status,confidence_score,raw_payload) values ('study',(select id from public.food_brands where name='Clean Label Project' limit 1),'heavy_metals','lead; arsenic; cadmium; mercury','lead avg 180.1; arsenic avg 184.6; cadmium avg 68.5; mercury avg 3.8; max lead 1576.5','ppb','elevated','2026-02-12','Ellipse Analytics (ISO 17025)','https://cleanlabelproject.org/dog-food-study/','verified_lab',null,jsonb_build_object('note','Independent ISO-17025 study: dry dog food averaged ~12.7x more lead and ~5.7x more arsenic than the human-consumables benchmark; highest single lead sample 1,576.5 ppb.','source_type','public_study','evidence_grade','verified_lab','product','Dry dog food category average (50 samples)','accessed','2026-06-25'));
insert into public.lab_tests(level,brand_id,contaminant_category,substance,result_value,unit,status,test_date,lab_name,source_url,evidence_status,confidence_score,raw_payload) values ('study',(select id from public.food_brands where name='Clean Label Project' limit 1),'heavy_metals','lead; arsenic; cadmium; mercury','lead avg 8.5; arsenic avg 13.9; cadmium avg 11.3; mercury avg 0.2','ppb','not_detected','2026-02-12','Ellipse Analytics (ISO 17025)','https://cleanlabelproject.org/dog-food-study/','verified_lab',null,jsonb_build_object('note','Fresh/frozen segment had the LOWEST contaminants of any segment, below the human-consumables benchmark; dry food had ~21x more lead than fresh/frozen.','source_type','public_study','evidence_grade','verified_lab','product','Fresh/frozen dog food category average (18 samples)','accessed','2026-06-25'));
insert into public.lab_tests(level,brand_id,contaminant_category,substance,result_value,unit,status,test_date,lab_name,source_url,evidence_status,confidence_score,raw_payload) values ('study',(select id from public.food_brands where name='Study: Kim et al. heavy metals in OTC dry dog foods' limit 1),'heavy_metals','arsenic; cadmium; lead; mercury (ICP-MS)','red-meat median Pb 0.091; As 0.037; Cd 0.013; Hg 0.0012','mg/Mcal','unknown','2018','Frontiers in Veterinary Science, 2018','https://www.frontiersin.org/journals/veterinary-science/articles/10.3389/fvets.2018.00264/full','verified_lab',null,jsonb_build_object('note','Frontiers in Vet Science 2018 (doi:10.3389/fvets.2018.00264). Fish diets higher As/Cd/Hg; red-meat diets higher Pb. Concluded foods generally safe for chronic consumption with occasional Pb outliers.','source_type','public_study','evidence_grade','verified_lab','product','51 over-the-counter dry dog foods','accessed','2026-06-25'));
insert into public.lab_tests(level,brand_id,contaminant_category,substance,result_value,unit,status,test_date,lab_name,source_url,evidence_status,confidence_score,raw_payload) values ('study',(select id from public.food_brands where name='Study: Koestel et al. BPA in canned dog food' limit 1),'bpa_bps','bisphenol A (BPA)','serum BPA increased significantly in all dogs','ng/mL','elevated','2017','Science of the Total Environment, 2017','https://www.cliniciansbrief.com/article/bisphenol-bpa-serum-pet-dogs-fed-canned-dog-food','verified_lab',null,jsonb_build_object('note','Sci Total Environ 2017;579:1804-1814. Both canned diets contained BPA incl. the ''BPA-free'' one; serum BPA rose significantly after 2 weeks and correlated with microbiome changes.','source_type','public_study','evidence_grade','verified_lab','product','2 canned diets (one labeled BPA-free); 14 dogs','accessed','2026-06-25'));
insert into public.lab_tests(level,brand_id,contaminant_category,substance,result_value,unit,status,test_date,lab_name,source_url,evidence_status,confidence_score,raw_payload) values ('study',(select id from public.food_brands where name='Study: Zhao et al. glyphosate in pet food' limit 1),'pesticides','glyphosate','~80 to 2000','ug/kg','unknown','2018','Environmental Pollution, 2018','https://news.cornell.edu/stories/2018/10/study-finds-glyphosate-cat-and-dog-food','verified_lab',null,jsonb_build_object('note','Environmental Pollution 2018 (Cornell). ALL 18 feeds contained glyphosate incl. one GMO-free certified; levels ~ <1% of human acceptable daily intake.','source_type','public_study','evidence_grade','verified_lab','product','18 dog & cat foods, 8 manufacturers','accessed','2026-06-25'));
insert into public.lab_tests(level,brand_id,contaminant_category,substance,result_value,unit,status,test_date,lab_name,source_url,evidence_status,confidence_score,raw_payload) values ('study',(select id from public.food_brands where name='Study: EWG PFAS in pet-food packaging' limit 1),'pfas','PFAS (PFBA, PFPeA, PFHxA, PFHpA, 6:2 FTCA, 6:2 diPAP, PFPrA); total fluorine','Purina Cat Chow 244.7 total PFAS; Kibbles ''n Bits 14.3','ppb','elevated','2022-11-03','Environmental Working Group, 2022','https://www.ewg.org/news-insights/news/2022/11/quibble-kibbles-forever-chemicals-pet-food-packaging-add-perils-home','verified_lab',null,jsonb_build_object('note','EWG Nov-2022 independent lab test of PACKAGING (total fluorine up to ~630 ppm); 7 PFAS detected. Purina Cat Chow Complete Chicken highest total PFAS (244.7 ppb). Migration into food not confirmed.','source_type','public_study','evidence_grade','verified_lab','product','11 bags, 7 popular brands','accessed','2026-06-25'));
insert into public.lab_tests(level,brand_id,contaminant_category,substance,result_value,unit,status,test_date,lab_name,source_url,evidence_status,confidence_score,raw_payload) values ('study',(select id from public.food_brands where name='Study/Recall: FDA Sportmix aflatoxin' limit 1),'mycotoxins','aflatoxins','up to 558 (threshold 20)','ppb','fail','2021-01-26','U.S. FDA / Missouri Dept. of Agriculture, 2021','https://www.fda.gov/animal-veterinary/outbreaks-and-advisories/fda-alert-certain-lots-sportmix-pet-food-recalled-potentially-fatal-levels-aflatoxin','verified_lab',null,jsonb_build_object('note','FDA/Missouri Dept Ag 2021: samples up to 558 ppb aflatoxin vs 20 ppb adulteration threshold; >130 dog deaths. Government lab-confirmed.','source_type','public_study','evidence_grade','verified_lab','product','Sportmix, Pro Pac, Nunn Better lots','accessed','2026-06-25'));
insert into public.lab_tests(level,brand_id,contaminant_category,substance,result_value,unit,status,test_date,lab_name,source_url,evidence_status,confidence_score,raw_payload) values ('brand',(select id from public.food_brands where name='Wellness' limit 1),'heavy_metals','arsenic; cadmium; lead; mercury','As 0.30; Cd 0.22; Pb 0.08; Hg 0.02 (example SKU)','mg/kg','pass','2026-04-03','third-party accredited lab (AOAC; unnamed)','https://www.wellnesspetfood.com/testing-results/','brand_claim',null,jsonb_build_object('note','Brand publishes a PUBLIC per-product heavy-metal results table with values + test dates (e.g. Simple Duck & Oatmeal As 0.30/Cd 0.22/Pb 0.08/Hg 0.02 mg/kg, all below NRC/FDA MTLs). Strong transparency but third-party lab unnamed and no downloadable independent COA -> graded brand_claim, values recorded.','source_type','brand_level_lab_report','evidence_grade','brand_claim','product','Multiple SKUs (public ''Testing Results'' page)','accessed','2026-06-25'));
insert into public.lab_tests(level,brand_id,contaminant_category,substance,result_value,unit,status,test_date,lab_name,source_url,evidence_status,confidence_score,raw_payload) values ('brand',(select id from public.food_brands where name='Orijen / Acana' limit 1),'heavy_metals','arsenic; cadmium; lead; mercury','dog As 0.89; Cd 0.09; Pb 0.23; Hg 0.02 | cat As 1.36','mg/kg','pass','2017-05-01','two third-party labs (AOAC; unnamed)','https://championpetfoods.com/on/demandware.static/-/Sites-cpf-corp-Library/default/dw7ff1cd03/pdf/Champion%20Petfoods%20White%20Paper-Heavy%20Metals.pdf','brand_claim',null,jsonb_build_object('note','Brand white paper (May 2017) reports 3-yr third-party AOAC averages well below NRC/FDA MTLs (dog As 0.89/Cd 0.09/Pb 0.23/Hg 0.02; cat As 1.36 mg/kg). Aggregate, dated 2017 (consider stale), labs unnamed -> brand_claim.','source_type','brand_level_lab_report','evidence_grade','brand_claim','product','Dog & cat foods (3-yr averages)','accessed','2026-06-25'));
insert into public.lab_tests(level,brand_id,contaminant_category,substance,result_value,unit,status,test_date,lab_name,source_url,evidence_status,confidence_score,raw_payload) values ('batch',(select id from public.food_brands where name='Open Farm' limit 1),'mycotoxins','Salmonella; E. coli; mycotoxins','','','unknown',null,'third-party QC lab (unnamed)','https://openfarmpet.com/pages/transparency','brand_claim',null,jsonb_build_object('note','[NEEDS REVIEW] Real lot-code traceability tool: scan/enter the bag lot code to trace ingredients and DOWNLOAD per-run QC lab results (salmonella/E.coli/mycotoxin clearance). No specific lot COA captured here; verify with a real product lot.','source_type','batch_lot_coa','evidence_grade','needs_review','product','Per-lot traceability + QC lab results','accessed','2026-06-25'));
