insert into public.admin_review_queue(entity_type,entity_id,priority,status,note) select 'lab_test', id, 2, 'open', 'Web-researched lab evidence - verify source & grade before surfacing' from public.lab_tests where id not in (select entity_id from public.admin_review_queue where entity_type='lab_test' and entity_id is not null);
insert into public.evidence_sources(title,publisher,url,source_type,summary) select 'Freshpet - third_party_lab_summary','Ellipse Analytics (ISO 17025) via Clean Label Project','https://cleanlabelproject.org/dog-food-study/','third_party_lab_summary','Only brand listed as Clean Label Project CERTIFIED in the Feb-2026 ISO-17025 study (independent testing for 100+ contaminants). Brand-level certification, not a per-lot COA.' where not exists (select 1 from public.evidence_sources where url='https://cleanlabelproject.org/dog-food-study/');
insert into public.evidence_sources(title,publisher,url,source_type,summary) select 'Study: Kim et al. heavy metals in OTC dry dog foods - public_study','Frontiers in Veterinary Science, 2018','https://www.frontiersin.org/journals/veterinary-science/articles/10.3389/fvets.2018.00264/full','public_study','Frontiers in Vet Science 2018 (doi:10.3389/fvets.2018.00264). Fish diets higher As/Cd/Hg; red-meat diets higher Pb. Concluded foods generally safe for chronic consumption with occasional Pb outliers.' where not exists (select 1 from public.evidence_sources where url='https://www.frontiersin.org/journals/veterinary-science/articles/10.3389/fvets.2018.00264/full');
insert into public.evidence_sources(title,publisher,url,source_type,summary) select 'Study: Koestel et al. BPA in canned dog food - public_study','Science of the Total Environment, 2017','https://www.cliniciansbrief.com/article/bisphenol-bpa-serum-pet-dogs-fed-canned-dog-food','public_study','Sci Total Environ 2017;579:1804-1814. Both canned diets contained BPA incl. the ''BPA-free'' one; serum BPA rose significantly after 2 weeks and correlated with microbiome changes.' where not exists (select 1 from public.evidence_sources where url='https://www.cliniciansbrief.com/article/bisphenol-bpa-serum-pet-dogs-fed-canned-dog-food');
insert into public.evidence_sources(title,publisher,url,source_type,summary) select 'Study: Zhao et al. glyphosate in pet food (Cornell) - public_study','Environmental Pollution, 2018','https://news.cornell.edu/stories/2018/10/study-finds-glyphosate-cat-and-dog-food','public_study','Environmental Pollution 2018 (Cornell). ALL 18 feeds contained glyphosate incl. one GMO-free certified; levels ~ <1% of human acceptable daily intake.' where not exists (select 1 from public.evidence_sources where url='https://news.cornell.edu/stories/2018/10/study-finds-glyphosate-cat-and-dog-food');
insert into public.evidence_sources(title,publisher,url,source_type,summary) select 'Study: EWG PFAS in pet-food packaging - public_study','Environmental Working Group, 2022','https://www.ewg.org/news-insights/news/2022/11/quibble-kibbles-forever-chemicals-pet-food-packaging-add-perils-home','public_study','EWG Nov-2022 independent lab test of PACKAGING (total fluorine up to ~630 ppm); 7 PFAS detected. Purina Cat Chow Complete Chicken highest total PFAS (244.7 ppb). Migration into food not confirmed.' where not exists (select 1 from public.evidence_sources where url='https://www.ewg.org/news-insights/news/2022/11/quibble-kibbles-forever-chemicals-pet-food-packaging-add-perils-home');
insert into public.evidence_sources(title,publisher,url,source_type,summary) select 'Study/Recall: FDA Sportmix aflatoxin (Midwestern Pet Foods) - public_study','U.S. FDA / Missouri Dept. of Agriculture, 2021','https://www.fda.gov/animal-veterinary/outbreaks-and-advisories/fda-alert-certain-lots-sportmix-pet-food-recalled-potentially-fatal-levels-aflatoxin','public_study','FDA/Missouri Dept Ag 2021: samples up to 558 ppb aflatoxin vs 20 ppb adulteration threshold; >130 dog deaths. Government lab-confirmed.' where not exists (select 1 from public.evidence_sources where url='https://www.fda.gov/animal-veterinary/outbreaks-and-advisories/fda-alert-certain-lots-sportmix-pet-food-recalled-potentially-fatal-levels-aflatoxin');
insert into public.evidence_sources(title,publisher,url,source_type,summary) select 'Wellness (WellPet) - brand_level_lab_report','third-party accredited lab (AOAC; unnamed)','https://www.wellnesspetfood.com/testing-results/','brand_level_lab_report','Brand publishes a PUBLIC per-product heavy-metal results table with values + test dates (e.g. Simple Duck & Oatmeal As 0.30/Cd 0.22/Pb 0.08/Hg 0.02 mg/kg, all below NRC/FDA MTLs). Strong transparency but third-party lab unnamed and no downloadable independent COA -> graded brand_claim, values recorded.' where not exists (select 1 from public.evidence_sources where url='https://www.wellnesspetfood.com/testing-results/');
insert into public.evidence_sources(title,publisher,url,source_type,summary) select 'Orijen / Acana (Champion Petfoods) - brand_level_lab_report','two third-party labs (AOAC; unnamed)','https://championpetfoods.com/on/demandware.static/-/Sites-cpf-corp-Library/default/dw7ff1cd03/pdf/Champion%20Petfoods%20White%20Paper-Heavy%20Metals.pdf','brand_level_lab_report','Brand white paper (May 2017) reports 3-yr third-party AOAC averages well below NRC/FDA MTLs (dog As 0.89/Cd 0.09/Pb 0.23/Hg 0.02; cat As 1.36 mg/kg). Aggregate, dated 2017 (consider stale), labs unnamed -> brand_claim.' where not exists (select 1 from public.evidence_sources where url='https://championpetfoods.com/on/demandware.static/-/Sites-cpf-corp-Library/default/dw7ff1cd03/pdf/Champion%20Petfoods%20White%20Paper-Heavy%20Metals.pdf');
